class Solution:
    def resultingString(self, s):
        def adj(a, b):
            d = (ord(a) - ord(b)) % 26
            return d == 1 or d == 25
        arr = list(s)
        changed = True
        while changed:
            changed = False
            for i in range(len(arr) - 1):
                if adj(arr[i], arr[i + 1]):
                    del arr[i:i + 2]
                    changed = True
                    break
        return ''.join(arr)

