class Solution:
    def resultingString(self, s):
        def adj(a, b):
            d = (ord(a) - ord(b)) % 26
            return d == 1 or d == 25
        stack = []
        for c in s:
            if stack and adj(stack[-1], c):
                stack.pop()
            else:
                stack.append(c)
        return ''.join(stack)

