var resultingString = function(s) {
    const adj = (a, b) => {
        const d = ((a.charCodeAt(0) - b.charCodeAt(0)) % 26 + 26) % 26;
        return d === 1 || d === 25;
    };
    const stack = [];
    for (const c of s) {
        if (stack.length && adj(stack[stack.length - 1], c)) {
            stack.pop();
        } else {
            stack.push(c);
        }
    }
    return stack.join('');
};
